package org.springframework.http; public class ResponseEntity<T> { public static BodyBuilder ok(){ return new BodyBuilder(); } public static BodyBuilder status(HttpStatus s){ return new BodyBuilder(); } public static class BodyBuilder { public BodyBuilder header(String k,String v){return this;} public BodyBuilder contentType(MediaType m){return this;} public <T> ResponseEntity<T> body(T body){return new ResponseEntity<>();}} }